    // ===============================================================
    // 2.1.5 MANEJO DE AMBITOS
    // ===============================================================

    // Agrega un nuevo ambito a la pila
    public static void pushScope(String nombre) {
        pilaTablas.push(new java.util.HashMap<>());
        nombresAmbitos.push(nombre);
    }
    
    // Elimina el ambito actual y lo guarda para imprimir despues
    public static void popScope() {
        if (!pilaTablas.isEmpty()) {
            java.util.HashMap<String, Simbolo> ambito = pilaTablas.pop();
            String nombre = nombresAmbitos.pop();
            int nivel = nombresAmbitos.size();
            
            todasLasTablas.add(new AmbitoInfo(nombre, ambito, nivel));
        }
    }

    // Imprime todas las tablas de simbolos al final del analisis
    public static void imprimirTodasLasTablas() {
        for (int i = todasLasTablas.size() - 1; i >= 0; i--) {
            AmbitoInfo a = todasLasTablas.get(i);
            
            String indentacion = "";
            for (int j = 0; j < a.nivel; j++) {
                indentacion += "               ";
            }
            
            System.out.println("\n" + indentacion + "=== TABLA DE SIMBOLOS: " + a.nombre + " ===");
            imprimirTabla(a.tabla, indentacion + "  ");
        }
        todasLasTablas.clear();
    }

    // ===============================================================
    // 2.1.6 OPERACIONES CON SIMBOLOS
    // ===============================================================

    // Registra una nueva variable en la tabla del ambito actual
    public static void agregarSimbolo(String nombre, String tipo, int linea) {
        if (pilaTablas.isEmpty()) return;
        java.util.HashMap<String, Simbolo> ambito = pilaTablas.peek();
        if (ambito.containsKey(nombre)) {
            errorSemantico("Linea " + linea + ": variable '" + nombre + "' ya fue declarada en este ambito.");
        } else {
            ambito.put(nombre, new Simbolo(nombre, tipo, linea, "variable"));
        }
    }

    // Registra un parametro en la tabla del ambito actual
    public static void agregarParametro(String nombre, String tipo, int linea) {
        if (pilaTablas.isEmpty()) return;
        java.util.HashMap<String, Simbolo> ambito = pilaTablas.peek();
        if (ambito.containsKey(nombre)) {
            errorSemantico("Linea " + linea + ": parametro '" + nombre + "' ya fue declarado en este ambito.");
        } else {
            ambito.put(nombre, new Simbolo(nombre, tipo, linea, "parametro"));
        }
    }

    // Muestra el contenido de una tabla de simbolos
    private static void imprimirTabla(java.util.HashMap<String, Simbolo> tabla, String indentacion) {
        if (tabla.isEmpty()) {
            System.out.println(indentacion + "(sin variables)");
            return;
        }
        System.out.println(indentacion + String.format("%-20s %-10s %-12s %s", "Variable", "Tipo", "Categoria", "Linea"));
        System.out.println(indentacion + String.format("%-20s %-10s %-12s %s", "--------", "----", "---------", "-----"));
        for (java.util.Map.Entry<String, Simbolo> e : tabla.entrySet()) {
            Simbolo s = e.getValue();
            System.out.println(indentacion + String.format("%-20s %-10s %-12s %s", s.nombre, s.tipo, s.categoria, s.linea));
        }
    }
    
    // Actualiza el tipo de un simbolo existente (para arreglos)
    public static void actualizarTipoSimbolo(String nombre, String nuevoTipo) {
        for (java.util.HashMap<String, Simbolo> ambito : pilaTablas) {
            if (ambito.containsKey(nombre)) {
                ambito.get(nombre).tipo = nuevoTipo;
                return;
            }
        }
    }

    // ===============================================================
    // 2.1.7 MANEJADORES DE ERRORES SINTACTICOS
    // ===============================================================

    // Error sintactico: token inesperado
    public void syntax_error(java_cup.runtime.Symbol s) {
        erroresSintacticos++;
        System.err.println(ANSI_BLUE + "[ERROR SINTACTICO] Linea " + s.left + ", columna " + s.right
                + ": token inesperado -> '" + s.value + "'" + ANSI_RESET);
    }

    // Error sintactico irrecuperable
    public void unrecovered_syntax_error(java_cup.runtime.Symbol s) {
        erroresSintacticos++;
        System.err.println(ANSI_BLUE_DARK + "[ERROR SINTACTICO IRRECUPERABLE] Linea " + s.left
                + ": no se pudo continuar el analisis." + ANSI_RESET);
    }

    // Mensaje de recuperacion de error
    public static void mensajeRecuperacion(String mensaje) {
        System.err.println(ANSI_CYAN + "[RECUPERACION] " + mensaje + ANSI_RESET);
    }

    // ===============================================================
    // 2.2 ANALISIS SEMANTICO
    // ===============================================================

    public static int erroresSemanticos = 0;

    // Reporta un error semantico
    public static void errorSemantico(String mensaje) {
        erroresSemanticos++;
        System.err.println(ANSI_RED + "[ERROR SEMANTICO] " + mensaje + ANSI_RESET);
    }

    // Busca un simbolo en toda la pila (de interno a externo)
    public static Simbolo buscarSimbolo(String nombre) {
        for (java.util.HashMap<String, Simbolo> ambito : pilaTablas) {
            if (ambito.containsKey(nombre)) return ambito.get(nombre);
        }
        return null;
    }

    // Verifica que una variable exista antes de usarla
    // Retorna: "tipo|nombre" o "error|?"
    public static String verificarUso(String nombre, int linea) {
        Simbolo s = buscarSimbolo(nombre);
        if (s == null) {
            errorSemantico("Linea " + linea + ": variable '" + nombre + "' no fue declarada.");
            return "error|?";
        }
        return s.tipo + "|" + nombre;
    }

    // ===============================================================
    // 2.2.1 VALIDACION DE TIPOS
    // ===============================================================
    // Compara dos tipos y valida compatibilidad
    // Recibe: tipo1, tipo2, operacion, linea
    // Retorna: el tipo resultante o "error|?"
    
    public static String validarTipos(String tipo1, String tipo2, String operacion, int linea) {
        
        String t1 = tipo1;
        String t2 = tipo2;
        
        // Extraer solo el tipo si viene con temporal (formato "tipo|temp")
        if (tipo1 != null && tipo1.contains("|")) {
            t1 = tipo1.split("\\|")[0];
        }
        if (tipo2 != null && tipo2.contains("|")) {
            t2 = tipo2.split("\\|")[0];
        }
        
        // Si algun tipo es error, propagar error
        if (t1.equals("error") || t2.equals("error")) return "error|?";
        
        // Tipos incompatibles
        if (!t1.equals(t2)) {
            if (operacion.equals("asignacion")) {
                errorSemantico("Linea " + linea 
                    + ": tipo incompatible en asignacion, se esperaba '" + t1 
                    + "' pero se encontro '" + t2 + "'.");
            } else if (operacion.equals("return")) {
                errorSemantico("Linea " + linea 
                    + ": tipo de retorno incorrecto, se esperaba '" + t1 
                    + "' pero se encontro '" + t2 + "'.");
            } else {
                errorSemantico("Linea " + linea 
                    + ": tipos incompatibles en operacion '" + operacion 
                    + "', se encontraron '" + t1 + "' y '" + t2 + "'.");
            }
            return "error|?";
        }
        
        // Para operadores relacionales, retorna bool
        if (operacion.equals("less_t") || operacion.equals("less_te") || 
            operacion.equals("greather_t") || operacion.equals("greather_te") ||
            operacion.equals("equal") || operacion.equals("n_equal")) {
            return "bool|?";
        }
        
        // Para otros casos, retorna el mismo tipo
        return t1 + "|?";
    }

